"use client";

import { useEffect, useState } from "react";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { ThemeProvider } from "next-themes";
import { Toaster } from "@/components/ui/toaster";
import { Toaster as Sonner } from "@/components/ui/sonner";
import { TooltipProvider } from "@/components/ui/tooltip";
import { authService } from "@/services/authService";
import { useAuthStore } from "@/store";

function AuthRehydrator() {
  const { user, setUser, setLoading, logout } = useAuthStore();

  useEffect(() => {
    if (user) return;
    setLoading(true);
    // Try a silent refresh first so an expired access token doesn't cause
    // getMe() to return null when the refresh token is still valid.
    authService.refresh()
      .catch(() => { /* refresh token also expired — user must log in again */ })
      .finally(() => {
        authService.getMe().then((me) => {
          setUser(me);
          setLoading(false);
        });
      });
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Proactive silent refresh every 13 min (access token lifetime is 15 min)
  useEffect(() => {
    if (!user) return;
    // Refresh every 13 min — access token lifetime is 15 min
    const interval = setInterval(async () => {
      try {
        await authService.refresh();
      } catch {
        logout();
      }
    }, 13 * 60 * 1000);
    return () => clearInterval(interval);
  }, [user, logout]);

  return null;
}

export function Providers({ children }: { children: React.ReactNode }) {
  const [queryClient] = useState(() => new QueryClient());

  return (
    <ThemeProvider attribute="class" defaultTheme="light" enableSystem>
      <QueryClientProvider client={queryClient}>
        <TooltipProvider>
          <AuthRehydrator />
          <Toaster />
          <Sonner />
          {children}
        </TooltipProvider>
      </QueryClientProvider>
    </ThemeProvider>
  );
}
